export const STATIC_SUTRAS: Sutra[] = [HEART_SUTRA, GREAT_COMPASSION_MANTRA];

import { GoogleGenAI, Type } from "@google/genai";
import { DailyWisdomData, ChatMessage } from "../types";
import { SYSTEM_INSTRUCTION } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using standard text model for reasoning and generation
const MODEL_NAME = 'gemini-3-flash-preview';

export const fetchDailyWisdom = async (): Promise<DailyWisdomData> => {
  try {
    const today = new Date().toISOString().split('T')[0];
    const prompt = "请提供一句简短的佛家经典名句（原文），并附带一段简短的、温暖的、与现代生活紧密相关的感悟/启示。";

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            quote: { type: Type.STRING, description: "The original Buddhist scripture quote" },
            source: { type: Type.STRING, description: "The name of the Sutra or source" },
            reflection: { type: Type.STRING, description: "A warm, modern life reflection based on the quote" }
          },
          required: ["quote", "source", "reflection"]
        }
      }
    });

    const json = JSON.parse(response.text || '{}');

    return {
      quote: json.quote || "心无挂碍，无有恐怖。",
      source: json.source || "心经",
      reflection: json.reflection || "放下的越多，得到的快乐越多。",
      date: today
    };
  } catch (error) {
    console.error("Error fetching wisdom:", error);
    // Fallback data
    return {
      quote: "本来无一物，何处惹尘埃。",
      source: "六祖坛经",
      reflection: "心若干净，世界便干净。不要让无谓的烦恼占据你的心灵。",
      date: new Date().toISOString().split('T')[0]
    };
  }
};

export const fetchRecitationEncouragement = async (): Promise<string> => {
  try {
    const prompt = "用户刚刚完成了今日的诵读打卡。请给予一句简短、温暖、充满法喜的鼓励，肯定他们的精进。";
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        maxOutputTokens: 100,
      }
    });
    return response.text || "随喜赞叹！精进修行，功德无量。";
  } catch (error) {
    return "随喜赞叹！每一份坚持，都是通往智慧的阶梯。";
  }
};

export const fetchSutraExplanation = async (sutraTitle: string, contentSnippet: string): Promise<string> => {
  try {
    const prompt = `请用通俗易懂的白话文解释以下经文片段，并简述其核心含义：\n\n经文：${sutraTitle}\n片段：${contentSnippet}`;
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      }
    });
    return response.text || "抱歉，暂时无法获取解释，请稍后再试。";
  } catch (error) {
    return "网络连接不稳定，请稍后重试。";
  }
};

export const streamChatResponse = async (history: ChatMessage[], newMessage: string, onChunk: (text: string) => void) => {
  try {
    const chat = ai.chats.create({
      model: MODEL_NAME,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      }))
    });

    const result = await chat.sendMessageStream({ message: newMessage });

    for await (const chunk of result) {
      if (chunk.text) {
        onChunk(chunk.text);
      }
    }
  } catch (error) {
    console.error("Chat error:", error);
    onChunk("抱歉，我正在冥想中（网络连接问题），请稍后再试。");
  }
};

import React, { useEffect, useState } from 'react';
import { DailyWisdomData } from '../types';
import { fetchDailyWisdom } from '../services/geminiService';

const LoadingLotus = () => (
  <div className="flex justify-center items-center py-20">
    <div className="animate-pulse text-zen-gold text-4xl">🪷</div>
  </div>
);

const DailyWisdom: React.FC = () => {
  const [data, setData] = useState<DailyWisdomData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadWisdom = async () => {
      const today = new Date().toISOString().split('T')[0];
      const cached = localStorage.getItem('daily_wisdom');

      if (cached) {
        const parsed: DailyWisdomData = JSON.parse(cached);
        if (parsed.date === today) {
          setData(parsed);
          setLoading(false);
          return;
        }
      }

      // Fetch new if no cache or date mismatch
      setLoading(true);
      const newData = await fetchDailyWisdom();
      localStorage.setItem('daily_wisdom', JSON.stringify(newData));
      setData(newData);
      setLoading(false);
    };

    loadWisdom();
  }, []);

  if (loading) return <LoadingLotus />;

  return (
    <div className="flex flex-col h-full p-6 items-center justify-center text-center animate-[fadeIn_0.5s_ease-out]">
      <div className="bg-white/80 backdrop-blur-sm rounded-2xl shadow-lg border border-stone-200 p-8 max-w-md w-full relative overflow-hidden">
        {/* Decorative Background Element */}
        <div className="absolute -top-10 -right-10 text-9xl text-stone-50 opacity-50 select-none pointer-events-none font-serif">
          禅
        </div>

        <h2 className="text-stone-400 text-sm tracking-[0.3em] uppercase mb-8">每日智慧</h2>

        <div className="mb-8">
          <p className="font-serif text-2xl md:text-3xl text-zen-brown leading-relaxed font-bold">
            「{data?.quote}」
          </p>
          <p className="text-zen-gold mt-4 font-serif italic text-right">
            —— 《{data?.source}》
          </p>
        </div>

        <div className="bg-zen-bg rounded-lg p-5 text-stone-600 text-sm md:text-base leading-relaxed text-left border-l-4 border-zen-gold">
          <span className="block font-bold mb-2 text-stone-500 text-xs tracking-wider">今日开示</span>
          {data?.reflection}
        </div>

        <div className="mt-8 text-xs text-stone-400">
          {data?.date} · 农历{new Intl.DateTimeFormat('zh-CN-u-ca-chinese').format(new Date())}
        </div>
      </div>
    </div>
  );
};

export default DailyWisdom;

import React, { useState } from 'react';
import { STATIC_SUTRAS } from '../constants';
import { Sutra } from '../types';
import { fetchSutraExplanation } from '../services/geminiService';

const SutraLibrary: React.FC = () => {
  const [selectedSutra, setSelectedSutra] = useState<Sutra | null>(null);
  const [explanation, setExplanation] = useState<string | null>(null);
  const [loadingExpl, setLoadingExpl] = useState(false);
  const [fontSize, setFontSize] = useState(18);

  const handleExplain = async () => {
    if (!selectedSutra) return;
    setLoadingExpl(true);
    // Explain the first 200 chars as a summary/context
    const snippet = selectedSutra.content.substring(0, 300);
    const result = await fetchSutraExplanation(selectedSutra.title, snippet);
    setExplanation(result);
    setLoadingExpl(false);
  };

  if (selectedSutra) {
    return (
      <div className="flex flex-col h-full bg-zen-paper overflow-hidden">
        {/* Reader Header */}
        <div className="flex items-center justify-between p-4 border-b border-stone-200 bg-white shadow-sm z-10">
          <button 
            onClick={() => { setSelectedSutra(null); setExplanation(null); }}
            className="text-stone-500 hover:text-zen-brown transition-colors"
          >
            ← 返回
          </button>
          <span className="font-serif font-bold text-zen-brown truncate px-2">{selectedSutra.title}</span>
          <div className="flex space-x-2">
            <button onClick={() => setFontSize(Math.max(14, fontSize - 2))} className="w-8 h-8 rounded-full border border-stone-300 text-stone-600 flex items-center justify-center text-xs">A-</button>
            <button onClick={() => setFontSize(Math.min(32, fontSize + 2))} className="w-8 h-8 rounded-full border border-stone-300 text-stone-600 flex items-center justify-center text-sm">A+</button>
          </div>
        </div>

        {/* Reader Content */}
        <div className="flex-1 overflow-y-auto p-6 md:p-10 scroll-smooth">
          <div className="max-w-2xl mx-auto">
            {/* Original Text */}
            <div 
              style={{ fontSize: `${fontSize}px`, lineHeight: '1.8' }}
              className="font-serif text-stone-800 text-justify mb-8 whitespace-pre-wrap tracking-wide"
            >
              {selectedSutra.content}
            </div>

            {/* Actions */}
            <div className="border-t border-dashed border-stone-300 pt-6 mt-6">
              {!explanation && !loadingExpl && (
                <button 
                  onClick={handleExplain}
                  className="w-full py-3 bg-stone-100 hover:bg-stone-200 text-zen-brown rounded-lg text-sm font-medium transition-colors border border-stone-200"
                >
                  ✨ AI 讲解经文大意
                </button>
              )}

              {loadingExpl && (
                <div className="text-center text-stone-400 py-4 text-sm animate-pulse">
                  般若正在为您解读...
                </div>
              )}

              {explanation && (
                <div className="bg-stone-50 rounded-lg p-5 border border-stone-100 animate-[fadeIn_0.5s]">
                  <h4 className="font-bold text-zen-brown mb-3 text-sm">经文大意与开示</h4>
                  <p className="text-stone-700 text-sm leading-relaxed whitespace-pre-wrap">{explanation}</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-4 h-full overflow-y-auto bg-zen-bg">
      <h2 className="text-2xl font-serif font-bold text-zen-brown mb-6 px-2 pt-2">经文藏经阁</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {STATIC_SUTRAS.map((sutra) => (
          <div 
            key={sutra.id}
            onClick={() => setSelectedSutra(sutra)}
            className="bg-white p-5 rounded-xl shadow-sm border border-transparent hover:border-zen-gold transition-all cursor-pointer group"
          >
            <div className="flex justify-between items-start mb-2">
              <h3 className="font-serif text-lg font-bold text-stone-800 group-hover:text-zen-gold transition-colors">
                {sutra.title}
              </h3>
              <span className="text-stone-300 text-xl group-hover:text-zen-gold">📖</span>
            </div>
            <p className="text-stone-500 text-sm leading-relaxed line-clamp-2">
              {sutra.shortDescription}
            </p>
          </div>
        ))}
        {/* Placeholder for future expansion */}
        <div className="bg-stone-100 border-2 border-dashed border-stone-200 p-5 rounded-xl flex flex-col items-center justify-center text-center opacity-70">
          <div className="text-2xl mb-2">📚</div>
          <p className="text-stone-500 text-sm">更多经文正在整理中...</p>
          <p className="text-xs text-stone-400 mt-1">您可在“解惑”中询问其他经文</p>
        </div>
      </div>
    </div>
  );
};

export default SutraLibrary;

import React, { useState, useEffect } from 'react';
import { RecitationLog, Sutra } from '../types';
import { STATIC_SUTRAS } from '../constants';
import { fetchRecitationEncouragement } from '../services/geminiService';

const RecitationTracker: React.FC = () => {
  const [logs, setLogs] = useState<RecitationLog[]>([]);
  const [selectedSutraId, setSelectedSutraId] = useState<string>(STATIC_SUTRAS[0].id);
  const [showEncouragement, setShowEncouragement] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const savedLogs = localStorage.getItem('recitation_logs');
    if (savedLogs) {
      setLogs(JSON.parse(savedLogs));
    }
  }, []);

  const handleCheckIn = async () => {
    setLoading(true);
    const sutra = STATIC_SUTRAS.find(s => s.id === selectedSutraId);
    if (!sutra) return;

    const newLog: RecitationLog = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      sutraTitle: sutra.title,
      timestamp: Date.now()
    };

    const updatedLogs = [newLog, ...logs];
    setLogs(updatedLogs);
    localStorage.setItem('recitation_logs', JSON.stringify(updatedLogs));

    // Get AI Encouragement
    const encouragement = await fetchRecitationEncouragement();
    setShowEncouragement(encouragement);
    setLoading(false);
  };

  const getStreak = () => {
    if (logs.length === 0) return 0;
    // Simple logic: check unique days in the logs
    const dates = new Set(logs.map(log => log.date.split('T')[0]));
    return dates.size;
  };

  const getTodayCount = () => {
    const today = new Date().toISOString().split('T')[0];
    return logs.filter(log => log.date.startsWith(today)).length;
  };

  return (
    <div className="h-full flex flex-col p-6 bg-zen-bg overflow-y-auto">
      {/* Header Stats */}
      <div className="grid grid-cols-2 gap-4 mb-8">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-stone-100 flex flex-col items-center">
          <span className="text-stone-400 text-xs tracking-widest uppercase mb-1">累计打卡天数</span>
          <span className="font-serif text-4xl text-zen-gold font-bold">{getStreak()}</span>
        </div>
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-stone-100 flex flex-col items-center">
          <span className="text-stone-400 text-xs tracking-widest uppercase mb-1">今日修持(遍)</span>
          <span className="font-serif text-4xl text-zen-brown font-bold">{getTodayCount()}</span>
        </div>
      </div>

      {/* Action Area */}
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-stone-100 mb-8">
        <h3 className="text-center font-serif text-lg text-stone-800 mb-4 font-bold">今日功课</h3>

        <div className="mb-6">
          <label className="block text-xs text-stone-400 mb-2 uppercase tracking-wide">选择经文</label>
          <select 
            value={selectedSutraId}
            onChange={(e) => setSelectedSutraId(e.target.value)}
            className="w-full bg-zen-bg border border-stone-200 text-stone-700 rounded-lg p-3 outline-none focus:border-zen-gold"
          >
            {STATIC_SUTRAS.map(s => (
              <option key={s.id} value={s.id}>{s.title}</option>
            ))}
          </select>
        </div>

        {!showEncouragement ? (
          <button
            onClick={handleCheckIn}
            disabled={loading}
            className={`w-full py-4 rounded-xl text-white font-bold tracking-widest shadow-md transition-all
              ${loading ? 'bg-stone-300 cursor-not-allowed' : 'bg-zen-gold hover:bg-amber-600 active:scale-[0.98]'}`}
          >
            {loading ? '记录中...' : '完成诵读 • 打卡'}
          </button>
        ) : (
          <div className="animate-[fadeIn_0.5s] bg-emerald-50 border border-emerald-100 rounded-xl p-5 text-center">
            <div className="text-emerald-600 text-2xl mb-2">🙏</div>
            <p className="text-emerald-800 font-serif font-medium leading-relaxed mb-4">
              {showEncouragement}
            </p>
            <button 
              onClick={() => setShowEncouragement(null)}
              className="text-xs text-emerald-600 font-bold hover:underline"
            >
              继续修持
            </button>
          </div>
        )}
      </div>

      {/* History */}
      <div className="flex-1">
        <h3 className="text-stone-400 text-xs uppercase tracking-widest mb-4 px-2">修持记录</h3>
        <div className="space-y-3">
          {logs.slice(0, 10).map(log => (
            <div key={log.id} className="bg-white px-4 py-3 rounded-xl border border-stone-100 flex justify-between items-center text-sm">
              <span className="text-stone-700 font-medium">{log.sutraTitle}</span>
              <span className="text-stone-400 text-xs">
                {new Date(log.timestamp).toLocaleString('zh-CN', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          ))}
          {logs.length === 0 && (
             <div className="text-center text-stone-400 py-8 text-sm">暂无记录，愿您今日精进。</div>
          )}
