import { GoogleGenAI, Type } from "@google/genai";
import { DailyWisdomData, ChatMessage, HistoryItem } from "../types";
import { SYSTEM_INSTRUCTION } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using standard text model for reasoning and generation
const MODEL_NAME = 'gemini-3-flash-preview';

export const fetchDailyWisdom = async (): Promise<DailyWisdomData> => {
  try {
    const today = new Date().toISOString().split('T')[0];
    const prompt = "请提供一句简短的佛家经典名句（原文），并附带一段简短的、温暖的、与现代生活紧密相关的感悟/启示。";

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            quote: { type: Type.STRING, description: "The original Buddhist scripture quote" },
            source: { type: Type.STRING, description: "The name of the Sutra or source" },
            reflection: { type: Type.STRING, description: "A warm, modern life reflection based on the quote" }
          },
          required: ["quote", "source", "reflection"]
        }
      }
    });

    const json = JSON.parse(response.text || '{}');

    return {
      quote: json.quote || "心无挂碍，无有恐怖。",
      source: json.source || "心经",
      reflection: json.reflection || "放下的越多，得到的快乐越多。",
      date: today
    };
  } catch (error) {
    console.error("Error fetching wisdom:", error);
    // Fallback data
    return {
      quote: "本来无一物，何处惹尘埃。",
      source: "六祖坛经",
      reflection: "心若干净，世界便干净。不要让无谓的烦恼占据你的心灵。",
      date: new Date().toISOString().split('T')[0]
    };
  }
};

export const fetchRecitationEncouragement = async (): Promise<string> => {
  try {
    const prompt = "用户刚刚完成了今日的诵读打卡。请给予一句简短、温暖、充满法喜的鼓励，肯定他们的精进。";
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        maxOutputTokens: 100,
      }
    });
    return response.text || "随喜赞叹！精进修行，功德无量。";
  } catch (error) {
    return "随喜赞叹！每一份坚持，都是通往智慧的阶梯。";
  }
};

export const fetchSutraExplanation = async (sutraTitle: string, contentSnippet: string): Promise<string> => {
  try {
    const prompt = `请用通俗易懂的白话文解释以下经文片段，并简述其核心含义：\n\n经文：${sutraTitle}\n片段：${contentSnippet}`;
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      }
    });
    return response.text || "抱歉，暂时无法获取解释，请稍后再试。";
  } catch (error) {
    return "网络连接不稳定，请稍后重试。";
  }
};

export const streamChatResponse = async (history: ChatMessage[], newMessage: string, onChunk: (text: string) => void) => {
  try {
    const chat = ai.chats.create({
      model: MODEL_NAME,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      }))
    });

    const result = await chat.sendMessageStream({ message: newMessage });

    for await (const chunk of result) {
      if (chunk.text) {
        onChunk(chunk.text);
      }
    }
  } catch (error) {
    console.error("Chat error:", error);
    onChunk("抱歉，我正在冥想中（网络连接问题），请稍后再试。");
  }
};

export const fetchBuddhistHistory = async (): Promise<HistoryItem> => {
  try {
    const prompt = "请讲述一个关于佛教历史的简短、引人入胜的故事或介绍一位重要人物/事件（例如佛陀生平、八大宗派祖师、经典翻译故事、佛教传入中国等）。返回JSON格式。";

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING, description: "Title of the historical event or figure" },
            period: { type: Type.STRING, description: "Time period (e.g., Tang Dynasty, 500 BC)" },
            content: { type: Type.STRING, description: "The story or description, around 150-200 words" }
          },
          required: ["title", "period", "content"]
        }
      }
    });

    const json = JSON.parse(response.text || '{}');
    return {
      title: json.title || "佛陀诞生",
      period: json.period || "公元前6世纪",
      content: json.content || "悉达多太子于蓝毗尼园无忧树下诞生..."
    };
  } catch (error) {
    return {
      title: "达摩东渡",
      period: "南北朝时期",
      content: "菩提达摩从印度渡海来到中国，将禅宗心法带入中土，被尊为中国禅宗初祖。"
    };
  }
};

import React, { useState, useEffect } from 'react';
import { HistoryItem } from '../types';
import { fetchBuddhistHistory } from '../services/geminiService';

const HistoryViewer: React.FC = () => {
  const [historyItem, setHistoryItem] = useState<HistoryItem | null>(null);
  const [loading, setLoading] = useState(false);

  const loadHistory = async () => {
    setLoading(true);
    const item = await fetchBuddhistHistory();
    setHistoryItem(item);
    setLoading(false);
  };

  useEffect(() => {
    // Try to load from session storage first to avoid refresh spamming API
    const cached = sessionStorage.getItem('current_history_item');
    if (cached) {
      setHistoryItem(JSON.parse(cached));
    } else {
      loadHistory();
    }
  }, []);

  useEffect(() => {
    if (historyItem) {
      sessionStorage.setItem('current_history_item', JSON.stringify(historyItem));
    }
  }, [historyItem]);

  return (
    <div className="h-full p-6 bg-zen-paper overflow-y-auto flex flex-col items-center">
      <h2 className="text-2xl font-serif font-bold text-zen-brown mb-6 pt-2">佛教史迹</h2>

      {loading && !historyItem ? (
         <div className="flex-1 flex items-center justify-center">
             <div className="text-zen-gold animate-pulse">翻阅典籍中...</div>
         </div>
      ) : (
        <div className="w-full max-w-md bg-white p-6 md:p-8 rounded-t-2xl rounded-b-lg shadow-md border-t-8 border-zen-brown relative flex-1 flex flex-col">
          {/* Decorative lines */}
          <div className="absolute top-0 left-0 w-full h-2 border-b border-stone-100"></div>

          <div className="mb-6 border-b border-stone-200 pb-4">
             <span className="inline-block bg-zen-bg text-zen-gray text-xs px-2 py-1 rounded mb-2 tracking-wider">
               {historyItem?.period}
             </span>
             <h3 className="text-2xl font-serif text-stone-800 font-bold leading-tight">
               {historyItem?.title}
             </h3>
          </div>

          <div className="flex-1">
            <p className="text-stone-600 leading-loose text-justify font-serif text-sm md:text-base">
              {historyItem?.content}
            </p>
          </div>

          <div className="mt-8 pt-6 border-t border-dashed border-stone-200 text-center">
            <button 
              onClick={loadHistory}
              disabled={loading}
              className={`px-6 py-2 rounded-full border border-zen-gold text-zen-gold hover:bg-zen-gold hover:text-white transition-all text-sm font-medium
                ${loading ? 'opacity-50 cursor-not-allowed' : ''}
              `}
            >
              {loading ? '探寻中...' : '阅读下一篇'}
            </button>
          </div>
        </div>
      )}

      <div className="text-xs text-stone-400 mt-6 text-center max-w-xs">
        历史如镜，映照本心。通过了解先贤行迹，我们可以更好地理解佛法的传承与精神。
      </div>
    </div>
  );
};

