import { GoogleGenAI, Type } from "@google/genai";
import { DailyWisdomData, ChatMessage, HistoryItem, Language } from "../types";
import { SYSTEM_INSTRUCTION } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using standard text model for reasoning and generation
const MODEL_NAME = 'gemini-3-flash-preview';

export const fetchDailyWisdom = async (lang: Language): Promise<DailyWisdomData> => {
  try {
    const today = new Date().toISOString().split('T')[0];
    const langPrompt = lang === 'en' 
      ? "Provide the response in English. Quote can be in original Chinese (Pinyin/English translation optional) or Sanskrit/Pali if appropriate, but keep the reflection in English." 
      : "请使用中文回答。";

    const prompt = `Please provide a short Buddhist scripture quote, and a warm, modern life reflection. ${langPrompt}`;

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            quote: { type: Type.STRING, description: "The Buddhist scripture quote" },
            source: { type: Type.STRING, description: "The name of the Sutra or source" },
            reflection: { type: Type.STRING, description: "A warm, modern life reflection" }
          },
          required: ["quote", "source", "reflection"]
        }
      }
    });

    const json = JSON.parse(response.text || '{}');

    return {
      quote: json.quote || (lang === 'en' ? "Form does not differ from Emptiness." : "色不异空。"),
      source: json.source || (lang === 'en' ? "Heart Sutra" : "心经"),
      reflection: json.reflection || (lang === 'en' ? "Let go of attachments to find true peace." : "放下执着，方得自在。"),
      date: today
    };
  } catch (error) {
    console.error("Error fetching wisdom:", error);
    return {
      quote: lang === 'en' ? "Originally there is not a single thing, where does dust alight?" : "本来无一物，何处惹尘埃。",
      source: lang === 'en' ? "Platform Sutra" : "六祖坛经",
      reflection: lang === 'en' ? "Keep your mind clear." : "心若干净，世界便干净。",
      date: new Date().toISOString().split('T')[0]
    };
  }
};

export const fetchRecitationEncouragement = async (lang: Language): Promise<string> => {
  try {
    const prompt = lang === 'en'
      ? "The user just finished reciting a Sutra. Give a short, warm, encouraging Buddhist message in English."
      : "用户刚刚完成了今日的诵读打卡。请给予一句简短、温暖、充满法喜的鼓励，肯定他们的精进。";

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        maxOutputTokens: 100,
      }
    });
    return response.text || (lang === 'en' ? "Rejoice in your diligence!" : "随喜赞叹！精进修行，功德无量。");
  } catch (error) {
    return lang === 'en' ? "Every step brings you closer to wisdom." : "随喜赞叹！每一份坚持，都是通往智慧的阶梯。";
  }
};

export const fetchSutraExplanation = async (sutraTitle: string, contentSnippet: string, lang: Language): Promise<string> => {
  try {
    const langPrompt = lang === 'en' ? "Explain in English." : "用通俗易懂的中文解释。";
    const prompt = `Explain this Buddhist text snippet briefly and simply. \n\nTitle: ${sutraTitle}\nSnippet: ${contentSnippet}\n\n${langPrompt}`;
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      }
    });
    return response.text || (lang === 'en' ? "Explanation currently unavailable." : "抱歉，暂时无法获取解释。");
  } catch (error) {
    return lang === 'en' ? "Network error, please try again." : "网络连接不稳定，请稍后重试。";
  }
};

export const streamChatResponse = async (history: ChatMessage[], newMessage: string, lang: Language, onChunk: (text: string) => void) => {
  try {
    const langInstruction = lang === 'en' ? " Reply in English." : " 请使用中文回答。";
    const chat = ai.chats.create({
      model: MODEL_NAME,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION + langInstruction,
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      }))
    });

    const result = await chat.sendMessageStream({ message: newMessage });

    for await (const chunk of result) {
      if (chunk.text) {
        onChunk(chunk.text);
      }
    }
  } catch (error) {
    console.error("Chat error:", error);
    onChunk(lang === 'en' ? "I am meditating (connection error)..." : "抱歉，我正在冥想中（网络连接问题），请稍后再试。");
  }
};

export const fetchBuddhistHistory = async (lang: Language): Promise<HistoryItem> => {
  try {
    const langPrompt = lang === 'en' ? "Respond in English." : "使用中文。";
    const prompt = `Tell a short, engaging story about Buddhist history or a significant figure (e.g., Buddha's life, Zen patriarchs). Return JSON. ${langPrompt}`;

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING, description: "Title of the historical event or figure" },
            period: { type: Type.STRING, description: "Time period" },
            content: { type: Type.STRING, description: "The story or description, around 150 words" }
          },
          required: ["title", "period", "content"]
        }
      }
    });

    const json = JSON.parse(response.text || '{}');
    return {
      title: json.title || "The Buddha",
      period: json.period || "Ancient India",
      content: json.content || "Siddhartha Gautama..."
    };
  } catch (error) {
    return {
      title: lang === 'en' ? "Bodhidharma" : "达摩东渡",
      period: lang === 'en' ? "5th Century" : "南北朝时期",
      content: lang === 'en' ? "Bodhidharma brought Zen to China..." : "菩提达摩从印度渡海来到中国，将禅宗心法带入中土，被尊为中国禅宗初祖。"
    };
  }
};

import React, { useEffect, useState } from 'react';
import { DailyWisdomData, Language } from '../types';
import { fetchDailyWisdom } from '../services/geminiService';
import { getTranslation } from '../translations';

const LoadingLotus = () => (
  <div className="flex justify-center items-center py-20">
    <div className="animate-pulse text-zen-gold text-4xl">🪷</div>
  </div>
);

interface Props {
  lang: Language;
}

const DailyWisdom: React.FC<Props> = ({ lang }) => {
  const [data, setData] = useState<DailyWisdomData | null>(null);
  const [loading, setLoading] = useState(true);
  const t = getTranslation(lang);

  useEffect(() => {
    const loadWisdom = async () => {
      // Create a cache key specific to language to avoid showing Chinese cached data in English mode
      const cacheKey = `daily_wisdom_${lang}`;
      const today = new Date().toISOString().split('T')[0];
      const cached = localStorage.getItem(cacheKey);

      if (cached) {
        const parsed: DailyWisdomData = JSON.parse(cached);
        if (parsed.date === today) {
          setData(parsed);
          setLoading(false);
          return;
        }
      }

      // Fetch new if no cache or date mismatch
      setLoading(true);
      const newData = await fetchDailyWisdom(lang);
      localStorage.setItem(cacheKey, JSON.stringify(newData));
      setData(newData);
      setLoading(false);
    };

    loadWisdom();
  }, [lang]);

  if (loading) return <LoadingLotus />;

  return (
    <div className="flex flex-col h-full p-6 items-center justify-center text-center animate-[fadeIn_0.5s_ease-out]">
      <div className="bg-white/80 backdrop-blur-sm rounded-2xl shadow-lg border border-stone-200 p-8 max-w-md w-full relative overflow-hidden">
        {/* Decorative Background Element */}
        <div className="absolute -top-10 -right-10 text-9xl text-stone-50 opacity-50 select-none pointer-events-none font-serif">
          禅
        </div>

        <h2 className="text-stone-400 text-sm tracking-[0.3em] uppercase mb-8">{t.daily_title}</h2>

        <div className="mb-8">
          <p className="font-serif text-2xl md:text-3xl text-zen-brown leading-relaxed font-bold">
            「{data?.quote}」
          </p>
          <p className="text-zen-gold mt-4 font-serif italic text-right">
            —— 《{data?.source}》
          </p>
        </div>

        <div className="bg-zen-bg rounded-lg p-5 text-stone-600 text-sm md:text-base leading-relaxed text-left border-l-4 border-zen-gold">
          <span className="block font-bold mb-2 text-stone-500 text-xs tracking-wider">{t.daily_source}</span>
          {data?.reflection}
        </div>

        <div className="mt-8 text-xs text-stone-400">
          {data?.date}
        </div>
      </div>
    </div>
  );
};

export default DailyWisdom;

