import { Sutra, Language } from '../types';
import { fetchSutraExplanation } from '../services/geminiService';
import { getTranslation } from '../translations';
import HistoryViewer from './HistoryViewer';

interface Props {
  lang: Language;
}

type Tab = 'SUTRA' | 'HISTORY';

const SutraLibrary: React.FC<Props> = ({ lang }) => {
  const [activeTab, setActiveTab] = useState<Tab>('SUTRA');
  const [selectedSutra, setSelectedSutra] = useState<Sutra | null>(null);
  const [explanation, setExplanation] = useState<string | null>(null);
  const [loadingExpl, setLoadingExpl] = useState(false);
  const [fontSize, setFontSize] = useState(18);

  const t = getTranslation(lang);

  const getSutraTitle = (sutra: Sutra) => lang === 'en' ? (sutra.titleEn || sutra.title) : sutra.title;
  const getSutraDesc = (sutra: Sutra) => lang === 'en' ? (sutra.shortDescriptionEn || sutra.shortDescription) : sutra.shortDescription;
  const getSutraContent = (sutra: Sutra) => lang === 'en' ? (sutra.contentEn || sutra.content) : sutra.content;

  const handleExplain = async () => {
    if (!selectedSutra) return;
    setLoadingExpl(true);
    // Explain the first 300 chars as a summary/context
    const content = getSutraContent(selectedSutra);
    const snippet = content.substring(0, 300);
    const result = await fetchSutraExplanation(getSutraTitle(selectedSutra), snippet, lang);
    setExplanation(result);
    setLoadingExpl(false);
  };

  // Reader View (Sutra selected)
  if (selectedSutra) {
    const displayTitle = getSutraTitle(selectedSutra);
    const displayContent = getSutraContent(selectedSutra);

    return (
      <div className="flex flex-col h-full bg-zen-paper overflow-hidden">
        {/* Reader Header */}
        <div className="flex items-center justify-between p-4 border-b border-stone-200 bg-white shadow-sm z-10">
          <button 
            onClick={() => { setSelectedSutra(null); setExplanation(null); }}
            className="text-stone-500 hover:text-zen-brown transition-colors"
          >
            ← {t.lib_back}
          </button>
          <span className="font-serif font-bold text-zen-brown truncate px-2 text-sm md:text-base max-w-[60%]">
            {displayTitle}
          </span>
          <div className="flex space-x-2">
            <button onClick={() => setFontSize(Math.max(14, fontSize - 2))} className="w-8 h-8 rounded-full border border-stone-300 text-stone-600 flex items-center justify-center text-xs">A-</button>
            <button onClick={() => setFontSize(Math.min(32, fontSize + 2))} className="w-8 h-8 rounded-full border border-stone-300 text-stone-600 flex items-center justify-center text-sm">A+</button>
          </div>
        </div>

        {/* Reader Content */}
        <div className="flex-1 overflow-y-auto p-6 md:p-10 scroll-smooth">
          <div className="max-w-2xl mx-auto">
            {/* Original Text */}
            <div 
              style={{ fontSize: `${fontSize}px`, lineHeight: '1.8' }}
              className={`font-serif text-stone-800 mb-8 whitespace-pre-wrap tracking-wide ${lang === 'zh' ? 'text-justify' : 'text-left'}`}
            >
              {displayContent}
            </div>

            {/* Actions */}
            <div className="border-t border-dashed border-stone-300 pt-6 mt-6">
              {!explanation && !loadingExpl && (
                <button 
                  onClick={handleExplain}
                  className="w-full py-3 bg-stone-100 hover:bg-stone-200 text-zen-brown rounded-lg text-sm font-medium transition-colors border border-stone-200"
                >
                  {t.lib_explain_btn}
                </button>
              )}

              {loadingExpl && (
                <div className="text-center text-stone-400 py-4 text-sm animate-pulse">
                  {t.lib_explain_loading}
                </div>
              )}

              {explanation && (
                <div className="bg-stone-50 rounded-lg p-5 border border-stone-100 animate-[fadeIn_0.5s]">
                  <h4 className="font-bold text-zen-brown mb-3 text-sm">AI Notes</h4>
                  <p className="text-stone-700 text-sm leading-relaxed whitespace-pre-wrap">{explanation}</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Main Library View
  return (
    <div className="h-full flex flex-col bg-zen-bg">
      {/* Header & Tabs */}
      <div className="p-4 bg-zen-bg sticky top-0 z-10 pb-2">
        <h2 className="text-2xl font-serif font-bold text-zen-brown mb-4 px-2 pt-2">{t.lib_title}</h2>
        <div className="flex p-1 bg-stone-200 rounded-lg">
          <button 
            onClick={() => setActiveTab('SUTRA')}
            className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${activeTab === 'SUTRA' ? 'bg-white text-zen-brown shadow-sm' : 'text-stone-500 hover:text-stone-700'}`}
          >
            {t.lib_tab_sutra}
          </button>
          <button 
            onClick={() => setActiveTab('HISTORY')}
            className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${activeTab === 'HISTORY' ? 'bg-white text-zen-brown shadow-sm' : 'text-stone-500 hover:text-stone-700'}`}
          >
            {t.lib_tab_history}
          </button>
        </div>
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-y-auto p-4 pt-0">
        {activeTab === 'SUTRA' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pb-20">
            {STATIC_SUTRAS.map((sutra) => (
              <div 
                key={sutra.id}
                onClick={() => setSelectedSutra(sutra)}
                className="bg-white p-5 rounded-xl shadow-sm border border-transparent hover:border-zen-gold transition-all cursor-pointer group"
              >
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-serif text-lg font-bold text-stone-800 group-hover:text-zen-gold transition-colors">
                    {getSutraTitle(sutra)}
                  </h3>
                  <span className="text-stone-300 text-xl group-hover:text-zen-gold">📖</span>
                </div>
                <p className="text-stone-500 text-sm leading-relaxed line-clamp-2">
                  {getSutraDesc(sutra)}
                </p>
              </div>
            ))}
          </div>
        ) : (
          <div className="pb-20">
            <HistoryViewer lang={lang} />
          </div>
        )}
      </div>
    </div>
  );
};

export default SutraLibrary;

import React, { useState, useEffect } from 'react';
import { RecitationLog, Language } from '../types';
import { STATIC_SUTRAS } from '../constants';
import { fetchRecitationEncouragement } from '../services/geminiService';
import { getTranslation } from '../translations';

interface Props {
  lang: Language;
}

const RecitationTracker: React.FC<Props> = ({ lang }) => {
  const [logs, setLogs] = useState<RecitationLog[]>([]);
  const [selectedSutraId, setSelectedSutraId] = useState<string>(STATIC_SUTRAS[0].id);
  const [showEncouragement, setShowEncouragement] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const t = getTranslation(lang);

  useEffect(() => {
    const savedLogs = localStorage.getItem('recitation_logs');
    if (savedLogs) {
      setLogs(JSON.parse(savedLogs));
    }
  }, []);

  const handleCheckIn = async () => {
    setLoading(true);
    const sutra = STATIC_SUTRAS.find(s => s.id === selectedSutraId);
    if (!sutra) return;

    // Save title in the current language context, or default to ID/Standard title for consistency
    // Here we save the localized title for display logs convenience
    const titleToSave = lang === 'en' ? (sutra.titleEn || sutra.title) : sutra.title;

    const newLog: RecitationLog = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      sutraTitle: titleToSave,
      timestamp: Date.now()
    };

    const updatedLogs = [newLog, ...logs];
    setLogs(updatedLogs);
    localStorage.setItem('recitation_logs', JSON.stringify(updatedLogs));

    // Get AI Encouragement
    const encouragement = await fetchRecitationEncouragement(lang);
    setShowEncouragement(encouragement);
    setLoading(false);
  };

  const getStreak = () => {
    if (logs.length === 0) return 0;
    const dates = new Set(logs.map(log => log.date.split('T')[0]));
    return dates.size;
  };

  const getTodayCount = () => {
    const today = new Date().toISOString().split('T')[0];
    return logs.filter(log => log.date.startsWith(today)).length;
  };

  return (
    <div className="h-full flex flex-col p-6 bg-zen-bg overflow-y-auto">
      {/* Header Stats */}
      <div className="grid grid-cols-2 gap-4 mb-8">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-stone-100 flex flex-col items-center">
          <span className="text-stone-400 text-xs tracking-widest uppercase mb-1">{t.rec_streak}</span>
          <span className="font-serif text-4xl text-zen-gold font-bold">{getStreak()}</span>
        </div>
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-stone-100 flex flex-col items-center">
          <span className="text-stone-400 text-xs tracking-widest uppercase mb-1">{t.rec_today}</span>
          <span className="font-serif text-4xl text-zen-brown font-bold">{getTodayCount()}</span>
        </div>
      </div>

      {/* Action Area */}
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-stone-100 mb-8">
        <h3 className="text-center font-serif text-lg text-stone-800 mb-4 font-bold">{t.rec_title}</h3>

        <div className="mb-6">
          <label className="block text-xs text-stone-400 mb-2 uppercase tracking-wide">{t.rec_select}</label>
          <select 
            value={selectedSutraId}
            onChange={(e) => setSelectedSutraId(e.target.value)}
            className="w-full bg-zen-bg border border-stone-200 text-stone-700 rounded-lg p-3 outline-none focus:border-zen-gold"
          >
            {STATIC_SUTRAS.map(s => (
              <option key={s.id} value={s.id}>
                {lang === 'en' ? (s.titleEn || s.title) : s.title}
              </option>
            ))}
          </select>
        </div>

        {!showEncouragement ? (
          <button
            onClick={handleCheckIn}
            disabled={loading}
            className={`w-full py-4 rounded-xl text-white font-bold tracking-widest shadow-md transition-all
              ${loading ? 'bg-stone-300 cursor-not-allowed' : 'bg-zen-gold hover:bg-amber-600 active:scale-[0.98]'}`}
          >
            {loading ? t.rec_btn_loading : t.rec_btn}
          </button>
        ) : (
          <div className="animate-[fadeIn_0.5s] bg-emerald-50 border border-emerald-100 rounded-xl p-5 text-center">
            <div className="text-emerald-600 text-2xl mb-2">🙏</div>
            <p className="text-emerald-800 font-serif font-medium leading-relaxed mb-4">
              {showEncouragement}
            </p>
            <button 
              onClick={() => setShowEncouragement(null)}
              className="text-xs text-emerald-600 font-bold hover:underline"
            >
              {t.rec_continue}
            </button>
          </div>
        )}
      </div>

      {/* History */}
      <div className="flex-1">
        <h3 className="text-stone-400 text-xs uppercase tracking-widest mb-4 px-2">{t.rec_history}</h3>
        <div className="space-y-3">
          {logs.slice(0, 10).map(log => (
            <div key={log.id} className="bg-white px-4 py-3 rounded-xl border border-stone-100 flex justify-between items-center text-sm">
              <span className="text-stone-700 font-medium">{log.sutraTitle}</span>
              <span className="text-stone-400 text-xs">
                {new Date(log.timestamp).toLocaleString(lang === 'zh' ? 'zh-CN' : 'en-US', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          ))}
          {logs.length === 0 && (
             <div className="text-center text-stone-400 py-8 text-sm">{t.rec_empty}</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default RecitationTracker;

