                >
                  {t.sub_interval_month}
                </button>
                <button
                  onClick={() => setBillingCycle('year')}
                  className={`flex-1 py-2 text-xs font-bold rounded-md transition-all flex items-center justify-center ${billingCycle === 'year' ? 'bg-white shadow-sm text-zen-brown' : 'text-stone-400'}`}
                >
                  {t.sub_interval_year}
                  <span className="ml-1 bg-red-100 text-red-500 text-[9px] px-1 rounded-full">{t.sub_save}</span>
                </button>
             </div>
           )}

           <div className={`p-4 rounded-lg border-2 mb-4 transition-all duration-300 ${isSubscribed ? 'border-zen-gold bg-amber-50' : 'border-stone-100 bg-stone-50'}`}>
              <div className="flex justify-between items-center">
                <div className="flex flex-col">
                  <span className="font-serif font-bold text-stone-700 text-lg">
                    {isSubscribed ? t.my_plan_pro : (billingCycle === 'month' ? t.sub_price_month : t.sub_price_year)}
                  </span>
                  {!isSubscribed && <span className="text-xs text-stone-400">{t.my_plan_pro}</span>}
                </div>
                <span className="text-2xl">
                  {isSubscribed ? '🪷' : '💎'}
