import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, Language } from '../types';
import { streamChatResponse } from '../services/geminiService';
import { getTranslation } from '../translations';

interface Props {
  lang: Language;
}

const ChatInterface: React.FC<Props> = ({ lang }) => {
  const t = getTranslation(lang);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Reset/Init chat when language changes
  useEffect(() => {
    if (messages.length === 0) {
      setMessages([
        {
          id: 'welcome',
          role: 'model',
          text: t.chat_welcome,
          timestamp: Date.now()
        }
      ]);
    }
  }, [lang, t.chat_welcome]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    const botMsgId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: botMsgId, role: 'model', text: '', timestamp: Date.now() }]);

    let accumulatedText = "";

    await streamChatResponse(messages, userMsg.text, lang, (chunk) => {
      accumulatedText += chunk;
      setMessages(prev => prev.map(msg => 
        msg.id === botMsgId ? { ...msg, text: accumulatedText } : msg
      ));
    });

    setIsTyping(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  // Active Chat View
  return (
    <div className="flex flex-col h-full bg-stone-50">
      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div 
              className={`max-w-[85%] rounded-2xl px-5 py-3 shadow-sm leading-relaxed text-sm md:text-base ${
                msg.role === 'user' 
                  ? 'bg-zen-brown text-white rounded-br-none' 
                  : 'bg-white text-stone-800 border border-stone-200 rounded-bl-none'
              }`}
            >
              {msg.role === 'model' && msg.text === '' ? (
                 <div className="flex space-x-1 items-center h-6">
                    <div className="w-1.5 h-1.5 bg-stone-400 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                    <div className="w-1.5 h-1.5 bg-stone-400 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                    <div className="w-1.5 h-1.5 bg-stone-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                 </div>
              ) : (
                <div className="whitespace-pre-wrap">{msg.text}</div>
              )}
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white border-t border-stone-200 pb-[max(1rem,env(safe-area-inset-bottom))]">
        <div className="flex items-end space-x-2 bg-stone-100 rounded-xl p-2 border border-stone-200 focus-within:border-zen-gold focus-within:bg-white transition-colors">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={t.chat_placeholder}
            className="flex-1 bg-transparent border-none outline-none resize-none max-h-32 text-base text-stone-800 p-2 placeholder-stone-400"
            rows={1}
            style={{ minHeight: '44px' }}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isTyping}
            className={`p-2 rounded-lg mb-0.5 transition-colors flex-shrink-0
              ${!input.trim() || isTyping 
                ? 'text-stone-300' 
                : 'text-zen-gold hover:bg-amber-50'}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-6 h-6">
              <path d="M3.478 2.405a.75.75 0 00-.926.94l2.432 7.905H13.5a.75.75 0 010 1.5H4.984l-2.432 7.905a.75.75 0 00.926.94 60.519 60.519 0 0018.445-8.986.75.75 0 000-1.218A60.517 60.517 0 003.478 2.405z" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState, useEffect } from 'react';
import { STATIC_SUTRAS } from '../constants';
import { Sutra, Language } from '../types';
import { fetchSutraExplanation } from '../services/geminiService';
import { getTranslation } from '../translations';
import HistoryViewer from './HistoryViewer';

interface Props {
  lang: Language;
}

type Tab = 'SUTRA' | 'HISTORY';

const SutraLibrary: React.FC<Props> = ({ lang }) => {
  const [activeTab, setActiveTab] = useState<Tab>('SUTRA');
  const [selectedSutra, setSelectedSutra] = useState<Sutra | null>(null);
  const [explanation, setExplanation] = useState<string | null>(null);
  const [loadingExpl, setLoadingExpl] = useState(false);
  const [fontSize, setFontSize] = useState(18);

  const t = getTranslation(lang);

  const getSutraTitle = (sutra: Sutra) => lang === 'en' ? (sutra.titleEn || sutra.title) : sutra.title;
  const getSutraDesc = (sutra: Sutra) => lang === 'en' ? (sutra.shortDescriptionEn || sutra.shortDescription) : sutra.shortDescription;
  const getSutraContent = (sutra: Sutra) => lang === 'en' ? (sutra.contentEn || sutra.content) : sutra.content;

  // Handle native Android back button for reader view
  useEffect(() => {
    if (selectedSutra) {
      const handleBack = (e: PopStateEvent) => {
        e.preventDefault();
        setSelectedSutra(null);
        setExplanation(null);
      };
      // Push state so back button closes reader instead of app
      window.history.pushState({ view: 'reader' }, '');
      window.addEventListener('popstate', handleBack);

      return () => {
        window.removeEventListener('popstate', handleBack);
      };
    }
  }, [selectedSutra]);

  const handleExplain = async () => {
    if (!selectedSutra) return;
    setLoadingExpl(true);
    // Explain the first 300 chars as a summary/context
    const content = getSutraContent(selectedSutra);
    const snippet = content.substring(0, 300);
    const result = await fetchSutraExplanation(getSutraTitle(selectedSutra), snippet, lang);
    setExplanation(result);
    setLoadingExpl(false);
  };

  const closeReader = () => {
    // Go back in history to remove the pushed state, which triggers popstate or just syncs history
    if (window.history.state?.view === 'reader') {
      window.history.back();
    } else {
      setSelectedSutra(null);
      setExplanation(null);
    }
  };

  // Reader View (Sutra selected)
  if (selectedSutra) {
    const displayTitle = getSutraTitle(selectedSutra);
    const displayContent = getSutraContent(selectedSutra);

    return (
      <div className="flex flex-col h-full bg-zen-paper overflow-hidden animate-[fadeIn_0.3s_ease-out]">
        {/* Reader Header */}
        <div className="flex items-center justify-between p-4 border-b border-stone-200 bg-white shadow-sm z-10 pt-[max(1rem,env(safe-area-inset-top))]">
          <button 
            onClick={closeReader}
            className="text-stone-500 hover:text-zen-brown transition-colors p-2 -ml-2"
          >
            <span className="text-lg">←</span> {t.lib_back}
          </button>
          <span className="font-serif font-bold text-zen-brown truncate px-2 text-sm md:text-base max-w-[50%]">
            {displayTitle}
          </span>
          <div className="flex space-x-2">
            <button onClick={() => setFontSize(Math.max(14, fontSize - 2))} className="w-8 h-8 rounded-full border border-stone-300 text-stone-600 flex items-center justify-center text-xs bg-white active:bg-stone-100">A-</button>
            <button onClick={() => setFontSize(Math.min(32, fontSize + 2))} className="w-8 h-8 rounded-full border border-stone-300 text-stone-600 flex items-center justify-center text-sm bg-white active:bg-stone-100">A+</button>
          </div>
        </div>

        {/* Reader Content */}
        <div className="flex-1 overflow-y-auto p-6 md:p-10 scroll-smooth pb-safe">
          <div className="max-w-2xl mx-auto">
            {/* Original Text */}
            <div 
              style={{ fontSize: `${fontSize}px`, lineHeight: '1.8' }}
              className={`font-serif text-stone-800 mb-8 whitespace-pre-wrap tracking-wide ${lang === 'zh' ? 'text-justify' : 'text-left'}`}
            >
              {displayContent}
            </div>

            {/* Actions */}
            <div className="border-t border-dashed border-stone-300 pt-6 mt-6 pb-20">
              {!explanation && !loadingExpl && (
                <button 
                  onClick={handleExplain}
                  className="w-full py-3 bg-stone-100 hover:bg-stone-200 text-zen-brown rounded-lg text-sm font-medium transition-colors border border-stone-200"
                >
                  {t.lib_explain_btn}
                </button>
              )}

              {loadingExpl && (
                <div className="text-center text-stone-400 py-4 text-sm animate-pulse">
                  {t.lib_explain_loading}
                </div>
              )}

              {explanation && (
                <div className="bg-stone-50 rounded-lg p-5 border border-stone-100 animate-[fadeIn_0.5s]">
                  <h4 className="font-bold text-zen-brown mb-3 text-sm">AI Notes</h4>
                  <p className="text-stone-700 text-sm leading-relaxed whitespace-pre-wrap">{explanation}</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Main Library View
  return (
    <div className="h-full flex flex-col bg-zen-bg">
      {/* Header & Tabs */}
      <div className="p-4 bg-zen-bg sticky top-0 z-10 pb-2 pt-4">
        <h2 className="text-2xl font-serif font-bold text-zen-brown mb-4 px-2 pt-2">{t.lib_title}</h2>
        <div className="flex p-1 bg-stone-200 rounded-lg">
          <button 
            onClick={() => setActiveTab('SUTRA')}
            className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${activeTab === 'SUTRA' ? 'bg-white text-zen-brown shadow-sm' : 'text-stone-500 hover:text-stone-700'}`}
          >
            {t.lib_tab_sutra}
          </button>
          <button 
            onClick={() => setActiveTab('HISTORY')}
            className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${activeTab === 'HISTORY' ? 'bg-white text-zen-brown shadow-sm' : 'text-stone-500 hover:text-stone-700'}`}
          >
            {t.lib_tab_history}
          </button>
        </div>
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-y-auto p-4 pt-0">
        {activeTab === 'SUTRA' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pb-20">
            {STATIC_SUTRAS.map((sutra) => (
              <div 
                key={sutra.id}
                onClick={() => setSelectedSutra(sutra)}
                className="bg-white p-5 rounded-xl shadow-sm border border-transparent hover:border-zen-gold transition-all cursor-pointer group"
              >
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-serif text-lg font-bold text-stone-800 group-hover:text-zen-gold transition-colors">
                    {getSutraTitle(sutra)}
                  </h3>
                  <span className="text-stone-300 text-xl group-hover:text-zen-gold">📖</span>
                </div>
                <p className="text-stone-500 text-sm leading-relaxed line-clamp-2">
                  {getSutraDesc(sutra)}
                </p>
              </div>
            ))}
          </div>
        ) : (
          <div className="pb-20">
            <HistoryViewer lang={lang} />
          </div>
        )}
      </div>
    </div>
  );
};

export default SutraLibrary;
